package com.helios.payments.consumer

import kotlinx.coroutines.*
import org.apache.kafka.clients.consumer.ConsumerConfig
import org.apache.kafka.clients.consumer.KafkaConsumer
import org.apache.kafka.common.errors.WakeupException
import org.apache.kafka.common.serialization.StringDeserializer
import org.slf4j.LoggerFactory
import org.slf4j.MDC
import java.time.Duration
import java.util.Properties

data class PaymentCompletedEvent(
    val paymentId: String,
    val accountId: String,
    val amount: Long,       // cents
    val currency: String,
    val correlationId: String,
    val completedAt: String // ISO-8601
)

class PaymentCompletedConsumer(
    private val bootstrapServers: String,
    private val groupId: String = "payment-completed-consumer",
    private val handler: suspend (PaymentCompletedEvent) -> Unit
) {
    private val log = LoggerFactory.getLogger(javaClass)
    private val consumer: KafkaConsumer<String, String> = createConsumer()
    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())

    private fun createConsumer(): KafkaConsumer<String, String> {
        val props = Properties().apply {
            put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers)
            put(ConsumerConfig.GROUP_ID_CONFIG, groupId)
            put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer::class.java.name)
            put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer::class.java.name)
            put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest")
            put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false") // manual commit for reliability
            put(ConsumerConfig.MAX_POLL_RECORDS_CONFIG, "100")
        }
        return KafkaConsumer(props)
    }

    fun start() {
        consumer.subscribe(listOf("payment-completed"))

        scope.launch {
            try {
                while (isActive) {
                    val records = withContext(Dispatchers.IO) {
                        consumer.poll(Duration.ofMillis(500))
                    }

                    for (record in records) {
                        val event = parseEvent(record.value()) ?: continue

                        MDC.put("correlationId", event.correlationId)
                        MDC.put("paymentId", event.paymentId)
                        try {
                            handler(event)
                            log.info("Processed payment-completed event")
                        } catch (e: Exception) {
                            log.error("Failed to process payment-completed event", e)
                            // TODO: dead-letter topic or retry strategy
                            throw e
                        } finally {
                            MDC.clear()
                        }
                    }

                    if (!records.isEmpty) {
                        withContext(Dispatchers.IO) { consumer.commitSync() }
                    }
                }
            } catch (_: WakeupException) {
                // expected on shutdown
            } finally {
                withContext(Dispatchers.IO) { consumer.close() }
                log.info("Consumer closed")
            }
        }
    }

    fun stop() {
        consumer.wakeup()
        scope.cancel()
    }

